type QRadarCredential struct {
	Type string
	// Authorized service token for QRadar Operations. [Guide to generate a token](https://www.ibm.com/docs/en/qradar-common?topic=app-creating-authorized-service-token-qradar-operations).
	Token *TokenCredential
	// Reference to existing Authorized Service Token.
	TokenId TokenCredentialId

	rawJSON json.RawMessage
}

func (q *QRadarCredential) GetType() string {
	if q == nil {
		return ""
	}
	return q.Type
}

func (q *QRadarCredential) GetToken() *TokenCredential {
	if q == nil {
		return nil
	}
	return q.Token
}

func (q *QRadarCredential) GetTokenId() TokenCredentialId {
	if q == nil {
		return ""
	}
	return q.TokenId
}

func (q *QRadarCredential) UnmarshalJSON(data []byte) error {
	var unmarshaler struct {
		Type string `json:"type"`
	}
	if err := json.Unmarshal(data, &unmarshaler); err != nil {
		return err
	}
	q.Type = unmarshaler.Type
	if unmarshaler.Type == "" {
		return fmt.Errorf("%T did not include discriminant type", q)
	}
	switch unmarshaler.Type {
	case "token":
		value := new(TokenCredential)
		if err := json.Unmarshal(data, &value); err != nil {
			return err
		}
		q.Token = value
	case "token_id":
		var valueUnmarshaler struct {
			TokenId TokenCredentialId `json:"value"`
		}
		if err := json.Unmarshal(data, &valueUnmarshaler); err != nil {
			return err
		}
		q.TokenId = valueUnmarshaler.TokenId
	}
	q.rawJSON = nil
	return nil
}

func (q QRadarCredential) MarshalJSON() ([]byte, error) {
	if err := q.validate(); err != nil {
		return nil, err
	}
	if q.Token != nil {
		return internal.MarshalJSONWithExtraProperty(q.Token, "type", "token")
	}
	if q.TokenId != "" {
		var marshaler = struct {
			Type    string            `json:"type"`
			TokenId TokenCredentialId `json:"value"`
		}{
			Type:    "token_id",
			TokenId: q.TokenId,
		}
		return json.Marshal(marshaler)
	}
	if len(q.rawJSON) > 0 {
		return q.rawJSON, nil
	}
	return nil, fmt.Errorf("type %T does not define a non-empty union type", q)
}

type QRadarCredentialVisitor interface {
	VisitToken(*TokenCredential) error
	VisitTokenId(TokenCredentialId) error
}

func (q *QRadarCredential) Accept(visitor QRadarCredentialVisitor) error {
	if q.Token != nil {
		return visitor.VisitToken(q.Token)
	}
	if q.TokenId != "" {
		return visitor.VisitTokenId(q.TokenId)
	}
	return fmt.Errorf("type %T does not define a non-empty union type", q)
}

func (q *QRadarCredential) validate() error {
	if q == nil {
		return fmt.Errorf("type %T is nil", q)
	}
	var fields []string
	if q.Token != nil {
		fields = append(fields, "token")
	}
	if q.TokenId != "" {
		fields = append(fields, "token_id")
	}
	if len(fields) == 0 {
		if q.Type != "" {
			if len(q.rawJSON) > 0 {
				return nil
			}
			return fmt.Errorf("type %T defines a discriminant set to %q but the field is not set", q, q.Type)
		}
		return fmt.Errorf("type %T is empty", q)
	}
	if len(fields) > 1 {
		return fmt.Errorf("type %T defines values for %s, but only one value is allowed", q, fields)
	}
	if q.Type != "" {
		field := fields[0]
		if q.Type != field {
			return fmt.Errorf(
				"type %T defines a discriminant set to %q, but it does not match the %T field; either remove or update the discriminant to match",
				q,
				q.Type,
				q,
			)
		}
	}
	return nil
}

